+            metric: self.metric,
+            id: self.id,
+        }
+    }
+}
+
+impl<'a> GlyphKeyTrait for BorrowedGlyphKey<'a> {
+    fn key<'k>(&'k self) -> BorrowedGlyphKey<'k> {
