+fn luaify(value: Value, is_top: bool) -> String {
+    match value {
+        Value::String(s) if is_top => format!("act.{s}"),
+        Value::String(s) => quote_lua_string(&s),
+        Value::Bool(true) => "true".to_string(),
+        Value::Bool(false) => "false".to_string(),
+        Value::Null => "nil".to_string(),
+        Value::U64(u) => u.to_string(),
+        Value::F64(u) => u.to_string(),
+        Value::I64(u) => u.to_string(),
+        Value::Array(a) => {
+            format!("wat {a:?}")
+        }
+        Value::Object(o) if is_top => {
+            for (k, v) in o {
+                let k = match k {
+                    Value::String(s) => s,
+                    _ => unreachable!(),
+                };
+                let arg = match v {
+                    Value::String(_) => format!(" {}", luaify(v, false)),
+                    Value::Array(a) => {
+                        let b: Vec<String> = a.into_iter().map(|v| luaify(v, false)).collect();
+                        format!("{{ {} }}", b.join(", "))
+                    }
+                    Value::I64(i) => format!("({i})"),
+                    Value::U64(i) => format!("({i})"),
+                    Value::F64(i) => format!("({i})"),
+                    _ => luaify(v, false),
+                };
+                return format!("act.{k}{arg}");
+            }
+            unreachable!()
+        }
+        Value::Object(o) => {
+            let mut fields = vec![];
+            for (k, v) in o {
+                let k = match k {
+                    Value::String(s) => s,
+                    _ => unreachable!(),
+                };
+                let arg = match v {
+                    Value::Null => continue,
+                    Value::String(_) => format!(" {}", luaify(v, false)),
+                    Value::Array(a) => {
+                        let b: Vec<String> = a.into_iter().map(|v| luaify(v, false)).collect();
+                        format!("{{ {} }}", b.join(", "))
+                    }
+                    Value::I64(i) => format!("({i})"),
+                    Value::U64(i) => format!("({i})"),
+                    Value::F64(i) => format!("({i})"),
+                    Value::Object(o) if o.is_empty() => continue,
+                    _ => luaify(v, false),
+                };
+                fields.push(format!("{k} = {arg}"));
+            }
+            format!("{{ {} }}", fields.join(", "))
+        }
+    }
+}
+
+fn quote_lua_string(s: &str) -> String {
+    let mut result = String::new();
+    result.push('\'');
+    for c in s.chars() {
+        match c {
+            '\u{07}' => {
+                result.push_str("\\a");
+            }
+            '\u{08}' => {
+                result.push_str("\\b");
+            }
+            '\u{0c}' => {
+                result.push_str("\\f");
+            }
+            '\n' => {
+                result.push_str("\\n");
+            }
+            '\r' => {
+                result.push_str("\\r");
+            }
+            '\t' => {
+                result.push_str("\\t");
+            }
+            '\u{0b}' => {
+                result.push_str("\\v");
+            }
+            '\\' => {
+                result.push_str("\\\\");
+            }
+            '"' => {
+                result.push_str("\\\"");
+            }
+            '\'' => {
+                result.push_str("\\'");
+            }
+            c if c.is_alphanumeric() || c.is_ascii_punctuation() => {
+                result.push(c);
+            }
+            _ => {
+                let b = c as u32;
+                result.push_str(&format!("\\u{{{b:x}}}"));
+            }
+        }
+    }
+    result.push('\'');
+    result
+}
