+    let action = luaify(dyn_action, true);
+    let key = lua_key_code(key);
+    let key = quote_lua_string(&key);
+
+    let mods = format!("{mods:?}").replace(" ", "");
+
+    format!("{{ key = {key}, mods = '{mods}', action = {action} }}")
+}
